{
  "schema": "rig.relay.architecture_assessment.v1",
  "title": "Agent Runtime Scaling: Feasibility Assessment",
  "scope": "Scale opencode agent runtime from single-process to 200+ concurrent agents via worker pools and distributed state",
  "current_architecture": {
    "process_model": "Single Node.js process. All agents run as Effect fibers on one event loop thread.",
    "state_model": "In-memory SynchronizedRef maps for session state, background jobs, agent registry. SQLite for persistent message storage via Drizzle.",
    "concurrency": "Cooperative fiber interleaving. CPU-bound tool execution (tree-sitter parsing, JSON processing) blocks all fibers.",
    "tool_execution": "All tools run in-process via Tool.define() → execute(). Shell commands spawn real OS processes via ChildProcessSpawner."
  },
  "step_1_worker_pool": {
    "feasibility": "HIGH",
    "estimated_effort": "2-3 sessions",
    "why_feasible": "Effect's structured concurrency + fiber model provides clean abstraction for dispatching work to worker threads. The tool execution boundary (Tool.define → execute) is a natural seam. The existing BackgroundJob service provides the pattern (Deferred-based signaling, SynchronizedRef state management).",
    "design": {
      "new_service": "WorkerPool.Service — wraps Node.js worker_threads behind an Effect interface",
      "interface": {
        "submit": "(target: WorkerTarget, payload: unknown) → Effect<Deferred<WorkerResult>>",
        "pool_size": "Configurable (default: os.cpus().length - 1)",
        "worker_path": "packages/opencode/src/worker/pool-worker.ts"
      },
      "worker_targets": [
        {"name": "cpu_tool", "tools": ["grep", "shell", "read_source", "read_lib", "smart_batch", "replace_symbol"], "reason": "These tools do CPU-heavy JSON processing, AST parsing, or regex work that blocks the event loop"},
        {"name": "bg_executor", "reason": "Offload background subagent LLM loops to worker threads instead of fiber-interleaving them on the main thread"}
      ],
      "integration_points": [
        {"file": "packages/opencode/src/tool/tool.ts", "change": "Add optional remote execution to Def interface — execute can either run in-process or dispatch via WorkerPool"},
        {"file": "packages/opencode/src/task/task.ts", "change": "Background jobs use WorkerPool.bg_executor instead of Effect.forkIn(scope)"},
        {"file": "packages/opencode/src/effect/app-runtime.ts", "change": "Add WorkerPool.defaultLayer to AppLayer"},
        {"file": "packages/opencode/src/effect/instance-state.ts", "change": "Make InstanceState serializable for cross-worker transport"}
      ],
      "risks": [
        {"risk": "Node.js worker_threads require file-based entry points — Effect's runtime can't be serialized across the postMessage boundary", "mitigation": "Each worker runs its own ManagedRuntime. Worker receives serialized Effect descriptions (service + params), not closures."},
        {"risk": "InstanceState (SynchronizedRef) can't cross worker boundary", "mitigation": "Workers are stateless for tool execution — they receive inputs, return outputs. Background agent workers maintain their own in-process state until step 2."},
        {"risk": "StructuredClone limitation — Schema types with functions/brands don't serialize", "mitigation": "Use Schema.parse/Schema.encode round-trip for all cross-worker data. The Effect Schema layer already does this."}
      ],
      "files_created": [
        "packages/opencode/src/worker/pool.ts",
        "packages/opencode/src/worker/pool-worker.ts",
        "packages/opencode/src/worker/pool.txt"
      ]
    }
  },
  "step_2_postgres_state": {
    "feasibility": "HIGH — already in progress",
    "estimated_effort": "3-5 sessions (partial completion in current codebase)",
    "current_state": "DatabaseAdapter, DatabaseConfig, and db.pg.ts already exist. Session messages persist to disk/SQLite via Session service. BackgroundJob state is purely in-memory (SynchronizedRef<Map>). Coordination state (task claims, path reservations) is file-based (JSONL).",
    "what_remains": [
      {"target": "BackgroundJob state", "current": "SynchronizedRef<Map<string, Active>> in memory", "needed": "Postgres-backed jobs table with periodic cleanup", "effort": "medium"},
      {"target": "Coordination state", "current": "docs/json/opencode/coordination/messages.v1.jsonl (file append)", "needed": "Optional Postgres backing (keep file-based as fallback)", "effort": "low"},
      {"target": "InstanceState", "current": "ScopedCache + in-memory Effect per instance", "needed": "Postgres-backed instance registry for worker process recovery", "effort": "medium"},
      {"target": "Session messages", "current": "SQLite via Drizzle (Session service)", "needed": "Already in Postgres migration plan — session.sql → session.pg.sql", "effort": "already tracked"}
    ],
    "design": {
      "key_interface": "Replace SynchronizedRef<Map<K, V>> with Database-backed Effect that reads/writes PG",
      "job_table_schema": "CREATE TABLE IF NOT EXISTS agent_jobs (id TEXT PRIMARY KEY, type TEXT, status TEXT, session_id TEXT, metadata JSONB, created_at TIMESTAMPTZ, completed_at TIMESTAMPTZ, output TEXT)"
    }
  },
  "step_3_multi_worker": {
    "feasibility": "MEDIUM-HIGH",
    "estimated_effort": "4-6 sessions",
    "why_feasible": "The Effect architecture with Layers + ManagedRuntime naturally supports multiple runtimes. Each worker can instantiate its own AppRuntime with a subset of services. The session-based isolation model (each agent session has a unique SessionID) maps cleanly to worker affinity.",
    "design": {
      "topology": "1 orchestrator process (main thread) + N worker processes (worker_threads). Each worker runs M agents.",
      "orchestrator_responsibility": "Accept new agent sessions, route to least-loaded worker, health-check workers",
      "worker_responsibility": "Run M agent loops concurrently via Effect fibers within its own event loop",
      "worker_count_formula": "N = max(1, os.cpus().length - 1), M = ceil(200 / N)",
      "communication": "Structured messages via SharedArrayBuffer ring buffer or postMessage (Effect.runPromise → worker response)",
      "session_affinity": "Agent SessionID → hash → worker index (consistent routing)",
      "key_changes": [
        {"file": "packages/opencode/src/effect/app-runtime.ts", "change": "Runtime becomes a service that can be instantiated per-worker, not a singleton"},
        {"file": "packages/opencode/src/session/prompt.ts", "change": "Prompt loop becomes serializable — can be sent to a worker and resumed"},
        {"file": "packages/opencode/src/tool/task.ts", "change": "Subagent task tool routes to remote worker (or same worker for affinity)"}
      ],
      "risks": [
        {"risk": "Effect's runtime is not natively fork()-friendly — Fiber IDs, ScopedCache are process-local", "mitigation": "Each worker gets a fresh ManagedRuntime. Cross-worker dependencies (BackgroundJob.list()) are proxied through the orchestrator's PG-backed state (step 2)."},
        {"risk": "worker_threads don't share memory — SynchronizedRef-based locks don't work across workers", "mitigation": "Step 2 eliminates shared in-memory state. Workers communicate through Postgres."},
        {"risk": "LLM provider rate limits — 200 concurrent agents hitting OpenAI", "mitigation": "Per-provider rate limiting is a middleware layer — add before queue dispatch."}
      ]
    }
  },
  "step_4_distributed_queue": {
    "feasibility": "LOW-MEDIUM",
    "estimated_effort": "6-10 sessions (depends on infrastructure choices)",
    "why_lower_feasibility": "Requires production Redis or PG queue infrastructure. No existing queue abstraction in the codebase. Cross-machine coordination needs leader election, health checks, and retry queues.",
    "design_options": [
      {"option": "Redis Bull/Queue", "pros": "Mature, battle-tested, delayed jobs, retries", "cons": "New dependency (redis), operational overhead"},
      {"option": "Postgres SKIP LOCKED", "pros": "No new infrastructure — reuses existing PG migration", "cons": "Polling overhead, no built-in delayed jobs", "already_exists": "Drizzle ORM + PG connection in codebase"},
      {"option": "RabbitMQ / NATS", "pros": "True message broker, pub/sub, routing", "cons": "New infrastructure, operational complexity"}
    ],
    "prerequisite_hardening": [
      "Step 2 (Postgres state) must be complete — queue needs the same PG infrastructure",
      "All agent state must be externalized — no in-memory SynchronizedRef maps",
      "Graceful worker shutdown and task re-queuing on crash"
    ],
    "recommended_approach": "Start with PG SKIP LOCKED (zero new deps), graduate to Redis Bull if throughput requirements exceed PG's polling capacity."
  },
  "dependencies_map": {
    "step_2_without_step_1": "Possible but limited — PG-backed state alone doesn't prevent single-thread blocking",
    "step_1_without_step_2": "Possible and valuable alone — worker pool removes CPU blocking without state changes",
    "step_3_without_steps_1_and_2": "Not recommended — multi-worker without shared state creates split-brain scenarios",
    "recommended_order": "Step 1 (WorkerPool) → Step 2 (Postgres state) → Step 3 (multi-worker) → Step 4 (distributed queue)",
    "quickest_first_value": "Step 1 alone eliminates the main blocking bottleneck (CPU-bound tools stalling the event loop) and takes 2-3 sessions"
  }
}
